import { Box, Button, Card, CardActions, CardContent, CardHeader, makeStyles, TextField } from '@material-ui/core'
import axios from 'axios';
import React, { useState } from 'react'

const useStyle = makeStyles(theme => {
    return {
        root: {
            '& .MuiCard-root': {
                '&:hover': {
                    transform: 'scale(1)',
                    boxShadow: '0px 0px 0px'
                  }
        }
    }
}})

function JoinClass() {
    const classes = useStyle();

    const [classCode, setClassCode] = useState('');

    const handleSubmit = (e) => {
        e.preventDefault();

        axios.post('http://localhost:80/api/studentLogin.php', sendData)
            .then((response) => {

                Cookies.set('studentID', response.data, {
                    expires: 1,
                    path: '/',
                    sameSite: 'strict'
                });

                if (response.data === 'Invalid') {
                    alert('Wrong Credentials');
                } else {
                    navigate('/studentDashboard');
                }
            })
            .catch((err) => {
                console.log(err);
            })
    }


    return (
        <Box className={classes.root}>
            <Card variant='outlined'>
                <CardHeader title='Join Classroom' />
                <CardContent>
                    <form onSubmit={handleSubmit} >
                        <TextField 
                        placeholder='Class Code' 
                        variant='outlined' 
                        value={classCode}
                        onChange={(e) => {setClassCode(e.target.value);}}
                        />
                    </form>
                </CardContent>
                <CardActions>
                    <Button size="small" variant='contained' color='secondary'>Join Classroom</Button>
                </CardActions>
            </Card>
        </Box>
    )
}

export default JoinClass
